// timezones.go
package httpdriver

import (
	"context"
	"net/http"

	"github.com/openmeterio/openmeter/api"
	"github.com/openmeterio/openmeter/pkg/framework/commonhttp"
	"github.com/openmeterio/openmeter/pkg/framework/transport/httptransport"
)

type (
	ListTimezonesRequest  struct{}
	ListTimezonesResponse []api.Timezone
	ListTimezonesHandler  httptransport.Handler[ListTimezonesRequest, ListTimezonesResponse]
)

func (h *handler) ListTimezones() ListTimezonesHandler {
	return httptransport.NewHandler(
		func(ctx context.Context, r *http.Request) (ListTimezonesRequest, error) {
			return ListTimezonesRequest{}, nil
		},
		func(ctx context.Context, request ListTimezonesRequest) (ListTimezonesResponse, error) {
			// populate from static data source
			return ListTimezonesResponse{}, nil
		},
		commonhttp.JSONResponseEncoderWithStatus[ListTimezonesResponse](http.StatusOK),
		httptransport.AppendOptions(
			h.options,
			httptransport.WithOperationName("listTimezones"),
		)...,
	)
}
